&sdtGridPagamentos.Clear()
//DUPLICATA For Each Order EmpCod, FilCod, PedCod, PedTmpFrpPgtoTip Where EmpCod = &EmpCod Where FilCod = &FilCod Where PedCod = &PedCod Where PedTmpFrpPgtoTip = TipoDuplicata.DUPLICATA Where PedTmpDupVlr > 0
&sdtGridPagamentosItem = new() &sdtGridPagamentosItem.EmpCod = EmpCod &sdtGridPagamentosItem.FilCod = FilCod &sdtGridPagamentosItem.PedCod = PedCod &sdtGridPagamentosItem.PedTmpDupCod = PedTmpDupCod &sdtGridPagamentosItem.PedTmpFrpPgtoTip = PedTmpFrpPgtoTip &SdtGridPagamentosItem.PedTmpMensagem = 'DUPLICATA R$ ' &sdtGridPagamentosItem.PedTmpDupVlr = PedTmpDupVlr &sdtGridPagamentos.Add(&sdtGridPagamentosItem) when none &sdtGridPagamentosItem = new() &sdtGridPagamentosItem.EmpCod = &EmpCod &sdtGridPagamentosItem.FilCod = &FilCod &sdtGridPagamentosItem.PedCod = &PedCod &sdtGridPagamentosItem.PedTmpDupCod = 0 &sdtGridPagamentosItem.PedTmpFrpPgtoTip = TipoDuplicata.DUPLICATA &SdtGridPagamentosItem.PedTmpMensagem = 'DUPLICATA R$ ' &sdtGridPagamentosItem.PedTmpDupVlr = 0 &sdtGridPagamentos.Add(&sdtGridPagamentosItem) EndFor
//CARTAO DÉBITO &PedTmpDupVlr = 0 For Each Order EmpCod, FilCod, PedCod, PedTmpFrpPgtoTip Where EmpCod = &EmpCod Where FilCod = &FilCod Where PedCod = &PedCod Where PedTmpFrpPgtoTip = TipoDuplicata.CARTAOD or PedTmpDupCreDeb = 1 Where PedTmpDupVlr > 0 Where PedTmpDupCreDeb = 1
&sdtGridPagamentosItem = new() &sdtGridPagamentosItem.EmpCod = &EmpCod &sdtGridPagamentosItem.FilCod = &FilCod &sdtGridPagamentosItem.PedCod = &PedCod &sdtGridPagamentosItem.PedTmpDupCod = PedTmpDupCod &sdtGridPagamentosItem.PedTmpDupVlr = PedTmpDupVlr &sdtGridPagamentosItem.PedTmpFrpPgtoTip = TipoDuplicata.CARTAOD &sdtGridPagamentosItem.PedTmpDupCreDeb = 1 &SdtGridPagamentosItem.PedTmpMensagem = 'CARTÃO DÉBITO R$ ' &sdtGridPagamentos.Add(&sdtGridPagamentosItem) When None &sdtGridPagamentosItem = new() &sdtGridPagamentosItem.EmpCod = &EmpCod &sdtGridPagamentosItem.FilCod = &FilCod &sdtGridPagamentosItem.PedCod = &PedCod &sdtGridPagamentosItem.PedTmpDupCod = 0 &sdtGridPagamentosItem.PedTmpDupVlr = 0 &sdtGridPagamentosItem.PedTmpFrpPgtoTip = TipoDuplicata.CARTAOD &sdtGridPagamentosItem.PedTmpDupCreDeb = 1 &SdtGridPagamentosItem.PedTmpMensagem = 'CARTÃO DÉBITO R$ ' &sdtGridPagamentos.Add(&sdtGridPagamentosItem) EndFor
//CARTAO Crédito &PedTmpDupVlr = 0 &QtdVezes = 0 For Each Order EmpCod, FilCod, PedCod, PedTmpFrpPgtoTip Where EmpCod = &EmpCod Where FilCod = &FilCod Where PedCod = &PedCod Where PedTmpFrpPgtoTip = TipoDuplicata.CARTAOC or PedTmpDupCreDeb = 2 Where PedTmpDupVlr > 0 Where PedTmpDupCreDeb = 2
&QtdVezes += 1 &PedTmpDupVlr += PedTmpDupVlr EndFor
if &PedTmpDupVlr > 0 &sdtGridPagamentosItem = new() &sdtGridPagamentosItem.EmpCod = &EmpCod &sdtGridPagamentosItem.FilCod = &FilCod &sdtGridPagamentosItem.PedCod = &PedCod &sdtGridPagamentosItem.PedTmpDupCod = 0 &sdtGridPagamentosItem.PedTmpDupVlr = &PedTmpDupVlr &sdtGridPagamentosItem.PedTmpFrpPgtoTip = TipoDuplicata.CARTAOC &sdtGridPagamentosItem.PedTmpDupCreDeb = 2 &SdtGridPagamentosItem.PedTmpMensagem = 'CARTÃO CRÉDITO ('+trim(str(&QtdVezes))+'X) R$ ' &sdtGridPagamentos.Add(&sdtGridPagamentosItem) Else &sdtGridPagamentosItem = new() &sdtGridPagamentosItem.EmpCod = &EmpCod &sdtGridPagamentosItem.FilCod = &FilCod &sdtGridPagamentosItem.PedCod = &PedCod &sdtGridPagamentosItem.PedTmpDupCod = 0 &sdtGridPagamentosItem.PedTmpDupVlr = &PedTmpDupVlr &sdtGridPagamentosItem.PedTmpFrpPgtoTip = TipoDuplicata.CARTAOC &sdtGridPagamentosItem.PedTmpDupCreDeb = 2 &SdtGridPagamentosItem.PedTmpMensagem = 'CARTÃO CRÉDITO R$ ' &sdtGridPagamentos.Add(&sdtGridPagamentosItem) EndIf
//CHEQUE For Each Order EmpCod, FilCod, PedCod, PedTmpFrpPgtoTip Where EmpCod = &EmpCod Where FilCod = &FilCod Where PedCod = &PedCod Where PedTmpFrpPgtoTip = TipoDuplicata.CHEQUET Where PedTmpDupVlr > 0
&sdtGridPagamentosItem = new() &sdtGridPagamentosItem.EmpCod = EmpCod &sdtGridPagamentosItem.FilCod = FilCod &sdtGridPagamentosItem.PedCod = PedCod &sdtGridPagamentosItem.PedTmpDupCod = PedTmpDupCod &sdtGridPagamentosItem.PedTmpDupVlr = PedTmpDupVlr &sdtGridPagamentosItem.PedTmpFrpPgtoTip = PedTmpFrpPgtoTip &SdtGridPagamentosItem.PedTmpMensagem = 'CHEQUE R$ ' &sdtGridPagamentos.Add(&sdtGridPagamentosItem) when none &sdtGridPagamentosItem = new() &sdtGridPagamentosItem.EmpCod = &EmpCod &sdtGridPagamentosItem.FilCod = &FilCod &sdtGridPagamentosItem.PedCod = &PedCod &sdtGridPagamentosItem.PedTmpDupCod = 0 &sdtGridPagamentosItem.PedTmpDupVlr = 0 &sdtGridPagamentosItem.PedTmpFrpPgtoTip = TipoDuplicata.CHEQUET &SdtGridPagamentosItem.PedTmpMensagem = 'CHEQUE R$ ' &sdtGridPagamentos.Add(&sdtGridPagamentosItem) EndFor
//DINHEIRO //&PedTmpDupVlr = 0 //For Each Order EmpCod, FilCod, PedCod, PedTmpFrpPgtoTip // Where EmpCod = &EmpCod // Where FilCod = &FilCod // Where PedCod = &PedCod // Where PedTmpFrpPgtoTip = TipoDuplicata.DINHEIRO // Where PedTmpDupVlr > 0 // // &PedTmpDupVlr += PedTmpDupVlr // //EndFor // //&sdtGridPagamentosItem = new() //&sdtGridPagamentosItem.EmpCod = &EmpCod //&sdtGridPagamentosItem.FilCod = &FilCod //&sdtGridPagamentosItem.PedCod = &PedCod //&sdtGridPagamentosItem.PedTmpDupVlr = &PedTmpDupVlr //&sdtGridPagamentosItem.PedTmpDupCod = 0 //&sdtGridPagamentosItem.PedTmpFrpPgtoTip = TipoDuplicata.DINHEIRO //&SdtGridPagamentosItem.PedTmpMensagem = 'DINHEIRO R$ ' //&sdtGridPagamentos.Add(&sdtGridPagamentosItem) //
